"use client";
import { useState, useEffect, useRef } from "react";
import { usePathname, useRouter } from "next/navigation";
import { useSession } from "@/lib/auth";
import { getSupabaseBrowserClient } from "@/lib/supabase/client";

export default function Header({
                                   navLinks = [],
                                   extraDropdownItems = []
                               }) {
    const [notifOpen, setNotifOpen] = useState(false);
    const [profileOpen, setProfileOpen] = useState(false);
    const headerRef = useRef(null);
    const router = useRouter();
    const pathname = usePathname();
    const { session, profile, loading } = useSession();
    const supabase = getSupabaseBrowserClient();

    // Реальные данные пользователя
    const userName = profile?.фио || session?.user?.email?.split("@")[0] || "Гость";
    const initials = userName.trim().substring(0, 2).toUpperCase();
    const userEmail = session?.user?.email || "";
    const role = profile?.роль?.название || "Читатель";

    // Выход из аккаунта
    const handleLogout = async () => {
        await supabase.auth.signOut();
        router.push("/login");
        router.refresh();
    };

    // Закрытие дропдаунов при клике вне хедера
    useEffect(() => {
        const handleClickOutside = (e) => {
            if (headerRef.current && !headerRef.current.contains(e.target)) {
                setNotifOpen(false);
                setProfileOpen(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    if (loading) return null; // или спиннер

    return (
        <header className="header" ref={headerRef}>
            <a href="/catalog" className="logo">
                <svg width="36" height="36" viewBox="0 0 40 40" fill="none" style={{ flexShrink: 0 }}>
                    <rect x="4" y="8" width="14" height="24" rx="2" fill="#ec9428" opacity="0.9" />
                    <rect x="10" y="6" width="14" height="24" rx="2" fill="#f6ca7d" opacity="0.9" />
                    <rect x="16" y="10" width="14" height="24" rx="2" fill="#4f7e4f" opacity="0.9" />
                </svg>
                Библиотека<span>Будущего</span>
            </a>

            <nav className="nav">
                {navLinks.map(link => (
                    <button
                        key={link.href}
                        className={`nav-link ${pathname === link.href ? "active" : ""}`}
                        onClick={() => router.push(link.href)}
                    >
                        {link.label}
                    </button>
                ))}
            </nav>

            <div className="header-right">
                <div className="dropdown">
                    <button className="icon-btn" onClick={() => { setNotifOpen(!notifOpen); setProfileOpen(false); }}>
                        🔔 <span className="badge">3</span>
                    </button>
                    {notifOpen && (
                        <div className="dropdown-menu">
                            <div className="dropdown-header">🔔 Уведомления</div>
                            <button className="dropdown-item">Прочитать все</button>
                            <button className="dropdown-item" onClick={() => setNotifOpen(false)} style={{ position: "absolute", top: 8, right: 8, padding: 4 }}>✕</button>
                        </div>
                    )}
                </div>

                <div className={`dropdown ${profileOpen ? "open" : ""}`}>
                    <button className="user-btn" onClick={() => { setProfileOpen(!profileOpen); setNotifOpen(false); }}>
                        <div className="avatar" style={{ background: "linear-gradient(135deg, var(--sage-500), var(--sage-400))" }}>{initials}</div>
                        <div style={{ textAlign: "left" }}>
                            <div className="user-name">{userName} ▼</div>
                            <div style={{ fontSize: 11, color: "var(--ink-400)", marginTop: -2 }}>{role}</div>
                        </div>
                    </button>
                    <div className="dropdown-menu">
                        <div className="dropdown-header">
                            <div className="dropdown-header-name">{userName}</div>
                            <div className="dropdown-header-email">{userEmail}</div>
                        </div>
                        <button className="dropdown-item" onClick={() => router.push("/dashboard")}>👤 Личный кабинет</button>
                        {extraDropdownItems.map((item, i) => (
                            <button key={i} className="dropdown-item" onClick={() => { item.onClick?.(); setProfileOpen(false); }}>{item.label}</button>
                        ))}
                        <div className="dropdown-divider" />
                        <button className="dropdown-item danger" onClick={handleLogout}>🚪 Выйти</button>
                    </div>
                </div>
            </div>
        </header>
    );
}